/**
 * One running serve bridge, read from $AGON_HOME/serve/<id>.json: the loopback url + bearer token a client attaches with, plus its session id / bound engine / start time / source file.
 */
// @kern-source: drive:39
export interface ServeConnection {
  url: string;
  token: string;
  sessionId: string;
  engineId: string;
  startedAt: string;
  file: string;
}

/**
 * Read every well-formed serve connection file in `dir` ($AGON_HOME/serve/). Skips partial/garbled files and any missing url/token/sessionId. Pure given the dir so the test drives it with a temp $AGON_HOME.
 */
// @kern-source: drive:48
export function listServeConnections(dir: string): ServeConnection[] {
  if (!existsSync(dir)) return [];
  let files: string[];
  try { files = readdirSync(dir).filter((f) => f.endsWith('.json')); }
  catch { return []; }
  const out: ServeConnection[] = [];
  for (const f of files) {
    try {
      const raw = JSON.parse(readFileSync(join(dir, f), 'utf-8')) as Record<string, unknown>;
      const url = typeof raw.url === 'string' ? raw.url : '';
      const token = typeof raw.token === 'string' ? raw.token : '';
      const sessionId = typeof raw.sessionId === 'string' ? raw.sessionId : '';
      if (!url || !token || !sessionId) continue;
      out.push({
        url, token, sessionId,
        engineId: typeof raw.engineId === 'string' ? raw.engineId : '',
        startedAt: typeof raw.startedAt === 'string' ? raw.startedAt : '',
        file: join(dir, f),
      });
    } catch { /* unreadable/partial — skip */ }
  }
  return out;
}

/**
 * Resolve which serve session to drive. With a --session arg: exact sessionId wins, else a unique substring match; ambiguous or no match is an error listing the candidates. With no arg: the only one, or the most-recently-started (by startedAt) when several are running. Returns { error } (never throws) so the command maps it to a clean message + exit 2.
 */
// @kern-source: drive:74
export function pickServeConnection(conns: ServeConnection[], sessionArg: string|undefined): { conn?: ServeConnection; error?: string } {
  if (conns.length === 0) {
    return { error: 'no running `agon serve` found. Start one (`agon serve --origin <ext-origin>`) and open the side panel, or pass --url + --token.' };
  }
  const needle = (sessionArg ?? '').trim();
  if (needle) {
    const exact = conns.filter((c) => c.sessionId === needle);
    const matches = exact.length > 0 ? exact : conns.filter((c) => c.sessionId.includes(needle));
    if (matches.length === 0) return { error: `no serve session matches "${needle}". Running: ${conns.map((c) => c.sessionId).join(', ')}` };
    if (matches.length > 1) return { error: `"${needle}" is ambiguous: ${matches.map((c) => c.sessionId).join(', ')}` };
    return { conn: matches[0] };
  }
  if (conns.length === 1) return { conn: conns[0] };
  const sorted = [...conns].sort((a, b) => (Date.parse(b.startedAt) || 0) - (Date.parse(a.startedAt) || 0));
  return { conn: sorted[0] };
}

/**
 * Pull complete Server-Sent-Events frames (each terminated by a blank line) out of a streamed buffer. JSON.parses each `data:` payload (a serialized LoggedEvent); skips `:` comment pings and unparseable blocks. Returns the parsed frames + the unterminated remainder to carry into the next read. Pure + exported so the test feeds it split/partial chunks.
 */
// @kern-source: drive:95
export function parseSseChunk(buffer: string): { frames: unknown[]; rest: string } {
  const frames: unknown[] = [];
  // Normalize CRLF → LF so the blank-line frame split works whether the source emits
  // `\n\n` (our bridge) or `\r\n\r\n`. Only touch the buffer when a `\r` is actually
  // present (our bridge never emits one) so the common path stays O(n), not O(n²) over
  // a long carried-over buffer.
  let rest = buffer.includes('\r') ? buffer.replace(/\r\n/g, '\n') : buffer;
  let idx = rest.indexOf('\n\n');
  while (idx !== -1) {
    const block = rest.slice(0, idx);
    rest = rest.slice(idx + 2);
    const dataLines = block
      .split('\n')
      .filter((l) => l.startsWith('data:'))
      .map((l) => l.slice(5).trim());
    if (dataLines.length > 0) {
      try { frames.push(JSON.parse(dataLines.join('\n'))); }
      catch { /* partial/garbled data — drop this block */ }
    }
    idx = rest.indexOf('\n\n');
  }
  return { frames, rest };
}

/**
 * Human label for a page tool the browser is executing (rendered as 'browser: <label>…'). Mirrors the side panel's own activity labels so the two surfaces read the same.
 */
// @kern-source: drive:123
export function agentActivityLabel(capability: string): string {
  switch (capability) {
    case 'readPage': return 'reading the page';
    case 'screenshot': return 'taking a screenshot';
    case 'click': return 'clicking';
    case 'type': return 'typing';
    case 'navigate': return 'navigating';
    default: return `running ${capability || 'a tool'}`;
  }
}

/**
 * True when this approval-request is the brain awaiting OUR decision: kind === 'approval-request' AND targetClientId is either absent (legacy broadcast — the driver is the submitter, so treat as ours) or equals our clientId. The browser panel runs the same check with ITS id and so skips a terminal-driven turn's prompt.
 */
// @kern-source: drive:136
export function approvalTargetsClient(event: Record<string,unknown>, myClientId: string): boolean {
  if (!event || event.kind !== 'approval-request') return false;
  const target = typeof event.targetClientId === 'string' ? event.targetClientId : '';
  return target === '' || target === myClientId;
}

/**
 * Build the backward-compatible /approval wire body shared by terminal drive and the REPL Chrome handler. `automated` is true only for the unattended --auto-approve path; interactive, non-interactive-deny, and REPL decisions pass false explicitly so audit provenance never has to infer how approval happened.
 */
// @kern-source: drive:144
export function buildApprovalPostBody(requestId: string, clientId: string, decision: 'approve'|'approve-session'|'deny'|'deny-session'|'abort', automated: boolean): { requestId: string; clientId: string; decision: 'approve'|'approve-session'|'deny'|'deny-session'|'abort'; automated: boolean } {
  return { requestId, clientId, decision, automated };
}

/**
 * Render one bridge BrainEvent (narrowed by `kind`) as a single terminal line, or null to skip. The engine's answer arrives as `engine`/`text`; a capability-request is shown as BROWSER activity (the panel, not us, executes it); approval-requests are handled by the interactive prompt, not rendered here. Pure + exported for the test.
 */
// @kern-source: drive:150
export function renderDriveEvent(event: Record<string,unknown>): string | null {
  if (!event || typeof event !== 'object') return null;
  const kind = typeof event.kind === 'string' ? event.kind : '';
  const str = (v: unknown): string => (typeof v === 'string' ? v : v == null ? '' : String(v));
  const oneLine = (v: unknown): string => str(v).replace(/\s+/g, ' ').trim();
  switch (kind) {
    case 'text':
      return oneLine(event.content) || null;
    case 'engine': {
      const eid = oneLine(event.engineId) || 'engine';
      return `${bold(cyan(`◆ ${eid}`))} ${oneLine(event.content)}`;
    }
    case 'tool': {
      const tool = oneLine(event.tool) || 'tool';
      const status = oneLine(event.status) || 'done';
      if (status === 'running') return dim(`  ⚒ ${tool} ${oneLine(event.input)}`.trimEnd());
      if (status === 'error') return red(`  ⚒ ${tool} — ${oneLine(event.output) || 'error'}`);
      return dim(`  ⚒ ${tool} ✓`);
    }
    case 'capability-request':
      return dim(`  ↪ browser: ${agentActivityLabel(oneLine(event.capability))}…`);
    case 'notice': {
      const msg = oneLine(event.message);
      if (!msg) return null;
      const level = oneLine(event.level);
      if (level === 'error') return red(`▲ ${msg}`);
      if (level === 'warning') return yellow(`▲ ${msg}`);
      return dim(msg);
    }
    case 'recap':
      return oneLine(event.summary) ? dim(`recap: ${oneLine(event.summary)}`) : null;
    default:
      // approval-request (prompted), confidence/context/provenance/question — no flat line.
      return null;
  }
}

/**
 * Drive ONE terminal turn against a running serve session: resolve the connection (explicit --url/--token, else discover the newest running serve), /attach to learn the ledger cursor + confirm the token, then run a blocking POST /send WHILE an SSE /events reader renders live events and answers our approval-requests (prompting the terminal unless --auto-approve). /send returns the terminal result; we drain the SSE ~1s after to catch the final engine answer the brain flushed just before its 200, then tear down. Sets exit 2 on a connection/auth/send failure.
 */
// @kern-source: drive:191
export async function runDrive(opts: { prompt: string; sessionArg?: string; url?: string; token?: string; engine?: string; autoApprove: boolean }): Promise<void> {
  // 1. Resolve the connection.
  let conn: ServeConnection | undefined;
  if (opts.url && opts.token) {
    conn = { url: opts.url, token: opts.token, sessionId: (opts.sessionArg ?? '').trim() || '(remote)', engineId: '', startedAt: '', file: '' };
  } else {
    const conns = listServeConnections(agonPath('serve'));
    const picked = pickServeConnection(conns, opts.sessionArg);
    if (picked.error || !picked.conn) { warn(picked.error ?? 'could not resolve a serve connection'); process.exitCode = 2; return; }
    conn = picked.conn;
    if (conns.length > 1 && !(opts.sessionArg ?? '').trim()) {
      info(dim(`  (${conns.length} serve sessions running — drove the newest; pass --session <id> to pick another)`));
    }
  }

  const base = conn.url.replace(/\/+$/, '');
  const token = conn.token;
  const jsonHeaders = { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' };
  const authHeaders = { 'Authorization': `Bearer ${token}` };
  const clientId = randomUUID();

  // 2. /attach — confirm the token + learn the cursor (SSE tails only NEW events) + the
  //    real session id (so the --url/--token path shows it instead of '(remote)').
  let fromSeq = 0;
  let sessionLabel = conn.sessionId;
  try {
    const res = await fetch(`${base}/attach`, { method: 'POST', headers: jsonHeaders });
    if (!res.ok) {
      warn(`attach failed (${res.status}) — ${res.status === 401 ? 'bad token' : res.status === 403 ? 'Origin/auth refused' : 'is the bridge URL right?'}`);
      process.exitCode = 2; return;
    }
    const body = await res.json() as { lastSeq?: number; sessionId?: string };
    fromSeq = typeof body.lastSeq === 'number' ? body.lastSeq : 0;
    if (typeof body.sessionId === 'string' && body.sessionId) sessionLabel = body.sessionId;
  } catch (err) {
    warn(`cannot reach the bridge at ${base} — is \`agon serve\` running? (${err instanceof Error ? err.message : String(err)})`);
    process.exitCode = 2; return;
  }

  header(`agon drive → ${bold(sessionLabel)} ${dim(`@ ${base}`)}`);
  info(dim('  driving your browser via the open side panel — keep it attached to this serve session.'));
  console.log(`${bold(green('› you'))} ${opts.prompt}`);

  // 3. Two concurrent connections. Set up the approval prompt + SSE reader first.
  const ctrl = new AbortController();
  let sawBrowserActivity = false;
  let gotAnswer = false;       // an engine/text answer was rendered (so we know to stop draining)
  let streamFailed = false;    // the SSE never established / dropped before we aborted it
  // Only hold a readline open when we'll actually prompt — keeps a non-interactive / --auto-approve
  // run from resuming stdin (so the process exits cleanly).
  const interactive = Boolean(process.stdin.isTTY);
  const rl = (interactive && !opts.autoApprove) ? createInterface({ input: process.stdin, output: process.stdout }) : null;

  const askApproval = async (tool: string, command: string, reason: string): Promise<'approve'|'approve-session'|'deny'|'abort'> => {
    if (opts.autoApprove) { console.log(dim(`  ✓ auto-approved: ${command}`)); return 'approve'; }
    console.log(yellow(`  ⚠ the agent wants to ${bold(tool)}${command ? `: ${command}` : ''}`));
    if (reason) console.log(dim(`    ${reason}`));
    // No interactive terminal (piped/CI) → deny rather than hang on a prompt nobody can answer.
    if (!rl) {
      warn('    non-interactive stdin and no --auto-approve → denying this action. Re-run with --auto-approve to allow page actions unattended.');
      return 'deny';
    }
    let ans = '';
    try { ans = (await rl.question(dim('    allow? [y]es · [a]lways · [n]o · [s]top: '))).trim().toLowerCase(); }
    catch { return 'deny'; } // stdin closed/errored mid-prompt → safe default
    if (ans === 'y' || ans === 'yes') return 'approve';
    if (ans === 'a' || ans === 'always') return 'approve-session';
    if (ans === 's' || ans === 'stop' || ans === 'abort') return 'abort';
    return 'deny';
  };

  const handleFrame = async (frame: unknown): Promise<void> => {
    const f = frame as { seq?: number; event?: Record<string, unknown> };
    // The SSE replays from `fromSeq`; skip anything at or before it (pre-turn history)
    // so only THIS turn's events render.
    if (typeof f.seq === 'number' && f.seq <= fromSeq) return;
    const event = f.event;
    if (!event || typeof event !== 'object') return;
    if (approvalTargetsClient(event, clientId)) {
      const decision = await askApproval(
        typeof event.tool === 'string' ? event.tool : 'act',
        typeof event.command === 'string' ? event.command : '',
        typeof event.reason === 'string' ? event.reason : '',
      );
      try {
        const approvalBody = buildApprovalPostBody(typeof event.requestId === 'string' ? event.requestId : '', clientId, decision, opts.autoApprove);
        const ar = await fetch(`${base}/approval`, { method: 'POST', headers: jsonHeaders, body: JSON.stringify(approvalBody) });
        if (!ar.ok) warn(`    approval may not have registered (server said ${ar.status}) — the turn could stall.`);
      } catch { warn('    could not send the approval — the turn may stall until it times out.'); }
      return;
    }
    const kind = typeof event.kind === 'string' ? event.kind : '';
    if (kind === 'question-request') {
      // This terminal driver has no free-text answer UI, so it must NOT leave the turn paused for
      // QUESTION_TIMEOUT_MS (180s) — immediately reply with the autonomous-proceed guidance (the
      // same push the old nudge gave) so the engine continues on its own. A future interactive
      // drive could prompt the terminal user here instead.
      const q = typeof event.prompt === 'string' ? event.prompt : '';
      if (q) console.log(dim(`  · agent asked: ${q.slice(0, 200)} — proceeding autonomously`));
      try {
        await fetch(`${base}/answer`, { method: 'POST', headers: jsonHeaders, body: JSON.stringify({ requestId: typeof event.requestId === 'string' ? event.requestId : '', clientId, answer: 'Proceed autonomously: decide the most reasonable next step and do it now — do not wait for further input from me.' }) });
      } catch { warn('    could not answer the agent question — the turn may stall until it times out.'); }
      return;
    }
    if (kind === 'capability-request') sawBrowserActivity = true;
    if (kind === 'engine' || kind === 'text') gotAnswer = true;
    const line = renderDriveEvent(event);
    if (line !== null) console.log(line);
  };

  const sseLoop = (async () => {
    try {
      const res = await fetch(`${base}/events?from=${fromSeq}`, { headers: authHeaders, signal: ctrl.signal });
      if (!res.ok || !res.body) { streamFailed = true; return; }
      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buf = '';
      for (;;) {
        const { done, value } = await reader.read();
        if (done) break;
        buf += decoder.decode(value, { stream: true });
        const parsed = parseSseChunk(buf);
        buf = parsed.rest;
        for (const f of parsed.frames) await handleFrame(f);
      }
    } catch {
      // ctrl.abort() at turn-end is expected; a drop BEFORE we abort is a real failure
      // (the turn ran without us seeing approvals/answer — surfaced after teardown).
      if (!ctrl.signal.aborted) streamFailed = true;
    }
  })();

  // 4. Drive the turn. /send blocks until the brain finishes; live events came on SSE.
  let result: { reason?: string } | undefined;
  let failed = false;
  try {
    const sendBody: Record<string, unknown> = { input: opts.prompt, clientId };
    if (opts.engine) sendBody.engineId = opts.engine;
    const res = await fetch(`${base}/send`, { method: 'POST', headers: jsonHeaders, body: JSON.stringify(sendBody) });
    if (!res.ok) { warn(`send failed (${res.status})`); process.exitCode = 2; failed = true; }
    else { result = (await res.json() as { result?: { reason?: string } }).result; }
  } catch (err) {
    warn(`the turn failed: ${err instanceof Error ? err.message : String(err)}`);
    process.exitCode = 2; failed = true;
  } finally {
    // /send resolved = the brain flushed its final answer to the ledger just before the 200.
    // Wait for the SSE poll to deliver that tail — bounded, and only until the answer lands
    // (or the stream is known dead) so we never hang or cut off a late answer.
    if (!failed) {
      const deadline = Date.now() + 2500;
      while (!gotAnswer && !streamFailed && Date.now() < deadline) {
        await new Promise((r) => setTimeout(r, 80));
      }
    }
    ctrl.abort();
    rl?.close();
    await sseLoop;
  }

  console.log('');
  if (result?.reason) warn(`ended: ${result.reason}`);
  else if (!failed) success('done.');
  if (!failed && streamFailed) {
    warn("couldn't read the live event stream — the turn ran, but its output/approvals may not have shown here. Try `agon attach --self` or check the side panel.");
  } else if (!failed && !sawBrowserActivity) {
    info(dim('  (no page tools ran — if you expected browser actions, make sure the side panel is open + attached to this serve session.)'));
  }
}

// @kern-source: drive:364
export const driveCommand: any = defineCommand({
  meta: {
    name: 'drive',
    description: 'Drive your browser from the terminal via a running `agon serve` + the open side panel (research, check a page design, navigate/read/screenshot)',
  },
  args: {
    prompt: {
      type: 'positional',
      description: 'What to do, e.g. "open the pricing page and tell me if the hero is cluttered"',
      required: false,
    },
    session: {
      type: 'string',
      description: 'Which serve session to drive (id or substring; default: the newest running one)',
      required: false,
    },
    url: {
      type: 'string',
      description: 'Bridge URL — skip auto-discovery (pair with --token)',
      required: false,
    },
    token: {
      type: 'string',
      description: 'Bearer token for --url',
      required: false,
    },
    engine: {
      type: 'string',
      alias: 'e',
      description: 'Per-turn engine override (defaults to the served session engine)',
      required: false,
    },
    'auto-approve': {
      type: 'boolean',
      description: "Auto-approve page-changing actions (unattended). Off = prompt in the terminal.",
      required: false,
    },
  },
  async run({ args }: { args: { prompt?: string; session?: string; url?: string; token?: string; engine?: string; 'auto-approve'?: boolean } }) {
    ensureAgonHome();
    const prompt = typeof args.prompt === 'string' ? args.prompt.trim() : '';
    if (!prompt) {
      info('Usage: `agon drive "<what to do>"` — drives your browser through a running `agon serve` + the open side panel.');
      info(dim('  e.g.  agon drive "open news.ycombinator.com and summarize the top 3 posts"'));
      info(dim('  --session <id>   pick a serve session    --auto-approve   act without prompting'));
      info(dim('  --url <u> --token <t>   attach by explicit url+token (no discovery)'));
      return;
    }
    if ((typeof args.url === 'string') !== (typeof args.token === 'string')) {
      warn('--url and --token must be given together.');
      process.exitCode = 2; return;
    }
    await runDrive({
      prompt,
      sessionArg: typeof args.session === 'string' ? args.session : undefined,
      url: typeof args.url === 'string' ? args.url : undefined,
      token: typeof args.token === 'string' ? args.token : undefined,
      engine: typeof args.engine === 'string' ? args.engine : undefined,
      autoApprove: args['auto-approve'] === true,
    });
  },
});
